   106→void GrpcClientImpl::onSuccess(std::unique_ptr<envoy::service::auth::v3::CheckResponse>&& response,
   107→                               Tracing::Span& span) {
   108→  ENVOY_LOG(trace, "Received CheckResponse: {}", response->DebugString());
   109→  ResponsePtr authz_response = std::make_unique<Response>(Response{});
   110→  if (response->status().code() == Grpc::Status::WellKnownGrpcStatus::Ok) {
   111→    span.setTag(TracingConstants::get().TraceStatus, TracingConstants::get().TraceOk);
   112→    authz_response->status = CheckStatus::OK;
   113→    if (response->has_ok_response()) {
   114→      const auto& ok_response = response->ok_response();
   115→      copyOkResponseMutations(authz_response, ok_response);
   116→    }
   117→  } else {
   118→    span.setTag(TracingConstants::get().TraceStatus, TracingConstants::get().TraceUnauthz);
   119→    authz_response->status = CheckStatus::Denied;
   120→
   121→    // The default HTTP status code for denied response is 403 Forbidden.
   122→    authz_response->status_code = Http::Code::Forbidden;
   123→    if (response->has_denied_response()) {
   124→      copyHeaderFieldIntoResponse(authz_response, response->denied_response().headers());
   125→
   126→      const uint32_t status_code = response->denied_response().status().code();
   127→      if (status_code > 0) {
   128→        authz_response->status_code = static_cast<Http::Code>(status_code);
   129→      }
   130→      authz_response->body = response->denied_response().body();
   131→    }
   132→  }
   133→
   134→  // OkHttpResponse.dynamic_metadata is deprecated. Until OkHttpResponse.dynamic_metadata is
   135→  // removed, it overrides dynamic_metadata field of the outer check response.
   136→  if (response->has_ok_response() && response->ok_response().has_dynamic_metadata()) {
   137→    authz_response->dynamic_metadata = response->ok_response().dynamic_metadata();
   138→  } else {
   139→    authz_response->dynamic_metadata = response->dynamic_metadata();
   140→  }
   141→
   142→  callbacks_->onComplete(std::move(authz_response));
   143→  callbacks_ = nullptr;
   144→}
