    17→
    18→InstanceStats Config::generateStats(const std::string& name, Stats::Scope& scope) {
    19→  const std::string final_prefix = fmt::format("ext_authz.{}.", name);
    20→  return {ALL_TCP_EXT_AUTHZ_STATS(POOL_COUNTER_PREFIX(scope, final_prefix),
    21→                                  POOL_GAUGE_PREFIX(scope, final_prefix))};
    22→}
    23→
    24→void Filter::callCheck() {
    25→  Filters::Common::ExtAuthz::CheckRequestUtils::createTcpCheck(
    26→      filter_callbacks_, check_request_, config_->includePeerCertificate(),
    27→      config_->includeTLSSession(), config_->destinationLabels());
    28→  // Store start time of ext_authz filter call
    29→  start_time_ = filter_callbacks_->connection().dispatcher().timeSource().monotonicTime();
    30→  status_ = Status::Calling;
    31→  config_->stats().active_.inc();
    32→  config_->stats().total_.inc();
    33→
    34→  calling_check_ = true;
    35→  client_->check(*this, check_request_, Tracing::NullSpan::instance(),
    36→                 filter_callbacks_->connection().streamInfo());
    37→  calling_check_ = false;
    38→}
    39→
    40→Network::FilterStatus Filter::onData(Buffer::Instance&, bool /* end_stream */) {
    41→  if (!filterEnabled(filter_callbacks_->connection().streamInfo().dynamicMetadata())) {
    42→    config_->stats().disabled_.inc();
    43→    return Network::FilterStatus::Continue;
    44→  }
    45→
    46→  if (status_ == Status::NotStarted) {
    47→    // By waiting to invoke the check at onData() the call to authorization service will have
    48→    // sufficient information to fill out the checkRequest_.
    49→    callCheck();
    50→  }
    51→  return filter_return_ == FilterReturn::Stop ? Network::FilterStatus::StopIteration
    52→                                              : Network::FilterStatus::Continue;
    53→}
    54→
    55→Network::FilterStatus Filter::onNewConnection() {
    56→  // Wait till onData() happens.
    57→  return Network::FilterStatus::Continue;
    58→}
    59→
    60→void Filter::onEvent(Network::ConnectionEvent event) {
    61→  if (event == Network::ConnectionEvent::RemoteClose ||
    62→      event == Network::ConnectionEvent::LocalClose) {
    63→    if (status_ == Status::Calling) {
    64→      // Make sure that any pending request in the client is cancelled. This will be NOP if the
    65→      // request already completed.
    66→      client_->cancel();
    67→      config_->stats().active_.dec();
    68→    }
    69→  }
    70→}
    71→
    72→void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
    73→  status_ = Status::Complete;
    74→  config_->stats().active_.dec();
    75→
    76→  switch (response->status) {
    77→  case Filters::Common::ExtAuthz::CheckStatus::OK:
    78→    config_->stats().ok_.inc();
    79→    // Add duration of call to dynamic metadata if applicable
    80→    if (start_time_.has_value()) {
    81→      ProtobufWkt::Value ext_authz_duration_value;
    82→      auto duration = filter_callbacks_->connection().dispatcher().timeSource().monotonicTime() -
    83→                      start_time_.value();
    84→      ext_authz_duration_value.set_number_value(
    85→          std::chrono::duration_cast<std::chrono::milliseconds>(duration).count());
    86→      (*response->dynamic_metadata.mutable_fields())["ext_authz_duration"] =
    87→          ext_authz_duration_value;
    88→    }
    89→    break;
    90→  case Filters::Common::ExtAuthz::CheckStatus::Error:
    91→    config_->stats().error_.inc();
    92→    break;
    93→  case Filters::Common::ExtAuthz::CheckStatus::Denied:
    94→    config_->stats().denied_.inc();
    95→    break;
    96→  }
    97→
    98→  if (!response->dynamic_metadata.fields().empty()) {
    99→
   100→    filter_callbacks_->connection().streamInfo().setDynamicMetadata(
   101→        NetworkFilterNames::get().ExtAuthorization, response->dynamic_metadata);
   102→  }
   103→
   104→  // Fail open only if configured to do so and if the check status was a error.
   105→  if (response->status == Filters::Common::ExtAuthz::CheckStatus::Denied ||
   106→      (response->status == Filters::Common::ExtAuthz::CheckStatus::Error &&
   107→       !config_->failureModeAllow())) {
   108→    config_->stats().cx_closed_.inc();
   109→    filter_callbacks_->connection().close(Network::ConnectionCloseType::NoFlush, "ext_authz_close");
   110→    filter_callbacks_->connection().streamInfo().setResponseFlag(
   111→        StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
   112→    filter_callbacks_->connection().streamInfo().setResponseCodeDetails(
   113→        response->status == Filters::Common::ExtAuthz::CheckStatus::Denied
   114→            ? Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzDenied
   115→            : Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
   116→  } else {
   117→    // Let the filter chain continue.
   118→    filter_return_ = FilterReturn::Continue;
   119→    if (config_->failureModeAllow() &&
   120→        response->status == Filters::Common::ExtAuthz::CheckStatus::Error) {
   121→      // Status is Error and yet we are configured to allow traffic. Click a counter.
   122→      config_->stats().failure_mode_allowed_.inc();
   123→    }
   124→
   125→    // We can get completion inline, so only call continue if that isn't happening.
   126→    if (!calling_check_) {
   127→      filter_callbacks_->continueReading();
   128→    }
   129→  }
   130→}
   131→
