    54→
    55→void CheckRequestUtils::setAttrContextPeer(envoy::service::auth::v3::AttributeContext::Peer& peer,
    56→                                           const Network::Connection& connection,
    57→                                           const std::string& service, const bool local,
    58→                                           bool include_certificate) {
    59→
    60→  // Set the address
    61→  auto addr = peer.mutable_address();
    62→  if (local) {
    63→    Envoy::Network::Utility::addressToProtobufAddress(
    64→        *connection.connectionInfoProvider().localAddress(), *addr);
    65→  } else {
    66→    Envoy::Network::Utility::addressToProtobufAddress(
    67→        *connection.connectionInfoProvider().remoteAddress(), *addr);
    68→  }
    69→
    70→  // Set the principal. Preferably the URI SAN, DNS SAN or Subject in that order from the peer's
    71→  // cert. Include the X.509 certificate of the source peer, if configured to do so.
    72→  auto ssl = connection.ssl();
    73→  if (ssl != nullptr) {
    74→    if (local) {
    75→      const auto uri_sans = ssl->uriSanLocalCertificate();
    76→      if (uri_sans.empty()) {
    77→        const auto dns_sans = ssl->dnsSansLocalCertificate();
    78→        if (dns_sans.empty()) {
